import React from "react";
import axios from "axios";
import Volu from './../Volu/Volu';
import * as cc from "react-bootstrap"
import Navbar from "./../Navbar/Navbar"

// import List from './components/itemList.js'

class Items extends React.Component{
    state = {
        items:[]
    };


    componentDidMount(){
    axios.get("http://localhost:5000/Volunteering").then(result => {
    const finalResult = result.data;
    console.log(finalResult) // array of object
    this.setState({items:finalResult})
  }).catch(err => {
    console.log("Error",err);
  });
   }

   render(){
    return(
        <div>
       <Navbar/>


        <ul>

          {this.state.items.map((element,index)=>(


            <cc.Card  key={index} style={{ width: '100rem' }}>

            <cc.Card.Body>

            <cc.Card.Text>
          Category 
          {element.Category}
          <br></br>

          Description
          {element.Description}
          <br></br>

          address
          {element.address}
          <br></br>

          company_id
          {element.company_id}
          <br></br>
           </cc.Card.Text>
          <cc.Button link href ='' variant="primary">more</cc.Button>
          </cc.Card.Body>
          </cc.Card>


          ))}
        </ul>
        </div>
    );
    };
}




export default Items;
